1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: string; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
17	
18	const BLOCK_SIZE = 3;
19	const RUNE_BLOCK_PRICE = 60;
20	
21	const computeBase = (items: Item[]): number => {
22	  if (
23	    items.length === BLOCK_SIZE &&
24	    items.every((item) => item.type === "rune")
25	  ) {
26	    return RUNE_BLOCK_PRICE;
27	  }
28	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
29	};
30	
31	const quoteStep = (step: Step): { premium: number } => {
32	  const base = computeBase(step.items);
33	  const firstInsurance = base * FIRST_INSURANCE_RATE;
34	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
35	};
36	
37	export const runScenario = (scenario: unknown): unknown => {
38	  const { steps } = scenario as Scenario;
39	  return { results: steps.map(quoteStep) };
40	};
